-- Chien -> humain, Fête, Volume 7

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de te lever pour chercher quelque chose et penser aux autres.',$$Joyeuse fête. J''ai observé ta façon de te lever pour chercher quelque chose et penser aux autres.
Tu te lèves pour toi. Pour chercher quelque chose. Et en chemin tu demandes si quelqu''un d''autre a besoin de quelque chose. Ce réflexe. Cette façon de transformer ton propre trajet en service potentiel pour les autres. Ce soir j''ai vu ça trois fois. Joyeuse fête, mon humain préféré.
Avec observation de tes trois trajets transformés en services pour les autres, — {prenom}, ton animal témoin de tes altruismes de passage 🚶$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gères quelqu''un qui monopolise toute la conversation.',$$Joyeuse fête. J''ai observé comment tu gères quelqu''un qui monopolise toute la conversation.
Tu écoutes. Longtemps. Puis doucement tu commences à élargir. Tu interpelles quelqu''un d''autre. Tu poses une question qui ouvre à d''autres voix. Tu libères la conversation sans que le monopoliseur ne se sente interrompu. Joyeuse fête, mon humain préféré.
Avec admiration pour ta chirurgie conversationnelle invisible, — {prenom}, ton animal expert en libérations de parole 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens mangent debout alors qu''il y a une table.',$$Joyeuse fête. Je comprends pas pourquoi les gens mangent debout alors qu''il y a une table.
La table est là. Avec des chaises. Et pourtant certains mangent debout appuyés contre le mur. Comme si rester debout c''était rester disponible pour bouger. Je mange toujours de la même façon dans le même endroit. Mais je comprends le besoin de liberté. Joyeuse fête, mon humain préféré.
Avec compréhension du manger debout comme liberté de mouvement et respect pour cette philosophie, — {prenom}, ton animal dont les habitudes alimentaires sont plus stables 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé l''expression de ton visage à chaque nouvelle arrivée.',$$Joyeuse fête. J''ai mémorisé l''expression de ton visage à chaque nouvelle arrivée.
Chaque fois c''est différent. Selon qui arrive. Un sourire qui commence dans les yeux avant la bouche pour certains. Un sourire qui commence à la bouche pour d''autres. Ces variations minuscules qui disent tout sur tes relations. Joyeuse fête, mon humain préféré.
Avec mémorisation de chaque expression d''accueil et sa signification relationnelle, — {prenom}, ton animal expert en microexpressions d''accueil 😊$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de disposer les verres propres sur le plateau.',$$Joyeuse fête. J''ai observé ta façon de disposer les verres propres sur le plateau.
Symétriquement. Avec de l''espace entre eux. Pour qu''ils ne se touchent pas. Ce soin pour les verres encore vides. Cette attention à ce qui va servir. Joyeuse fête, mon humain préféré.
Avec observation de ton soin pour les verres vides et sa signification de préparation attentive, — {prenom}, ton animal expert en préparations du contenant 🥂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réponds quand quelqu''un te demande comment tu vas vraiment.',$$Joyeuse fête. J''ai observé comment tu réponds quand quelqu''un te demande comment tu vas vraiment.
C''est arrivé une fois ce soir. Quelqu''un t''a demandé comment tu allais et t''a regardé vraiment en attendant la vraie réponse. Et tu l''as donnée. Brièvement. Honnêtement. Juste ce qu''il fallait. Joyeuse fête, mon humain préféré.
Avec observation de ta réponse juste à la question vraie et son équilibre parfait, — {prenom}, ton animal gardien de tes moments d''honnêteté dosée 💛$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens repartent toujours avec les mêmes affaires.',$$Joyeuse fête. Je comprends pas pourquoi les gens repartent toujours avec les mêmes affaires.
Ils arrivent avec un manteau. Ils repartent avec le manteau. Rien de la fête ne reste sur eux matériellement. Seulement des souvenirs. Peut-être que les souvenirs pèsent plus que les objets. Joyeuse fête, mon humain préféré.
Avec réflexion sur le poids immatériel des souvenirs comparé aux objets, — {prenom}, ton animal philosophe de ce qu''on emporte vraiment 🧥$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de faire la transition entre le repas et l''après-repas.',$$Joyeuse fête. J''ai étudié ta façon de faire la transition entre le repas et l''après-repas.
Tu proposes quelque chose. Du dessert. Du café. Une question qui change le sujet. Tu guides doucement la soirée vers sa prochaine phase. Sans l''annoncer. Sans rupture. Joyeuse fête, mon humain préféré.
Avec observation de ta conduite invisible du flux de la soirée, — {prenom}, ton animal expert en transitions sans rupture 🔄$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de regarder quelqu''un qui te raconte quelque chose de triste.',$$Joyeuse fête. J''ai observé ta façon de regarder quelqu''un qui te raconte quelque chose de triste.
Tu ne cherches pas à résoudre immédiatement. Tu écoutes d''abord. Tu laisses la tristesse exister dans la conversation. Et puis tu dis quelque chose de simple et de juste. Joyeuse fête, mon humain préféré.
Avec admiration pour ta façon d''accueillir le difficile sans le fuir ni le noyer, — {prenom}, ton animal témoin de ta sagesse émotionnelle 💙$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gères la fin d''une bouteille.',$$Joyeuse fête. J''ai observé comment tu gères la fin d''une bouteille.
Tu la poses de côté. Tu en ouvres une autre. Sans en faire un événement. Sans que la transition soit une interruption. La soirée continue. Joyeuse fête, mon humain préféré.
Avec admiration pour ta gestion des fins de bouteille sans jointure visible, — {prenom}, ton animal expert en continuités invisibles 🍾$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens comparent les fêtes entre elles.',$$Joyeuse fête. Je comprends pas pourquoi les gens comparent les fêtes entre elles.
Tu te souviens de la fête d''il y a deux ans ? Ah oui celle où. Et untel était là. Cette façon de placer la soirée dans une histoire. De la situer dans un récit collectif. Peut-être que les fêtes sont des chapitres. Joyeuse fête, mon humain préféré.
Avec compréhension des fêtes comme chapitres d''un récit collectif et sa belle logique, — {prenom}, ton animal réconcilié avec la comparaison des soirées 📚$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé tes moments où tu t''es laissé aller à ne rien faire.',$$Joyeuse fête. J''ai mémorisé tes moments où tu t''es laissé aller à ne rien faire.
Trois fois. Trois moments où tu t''es assis et tu n''as rien fait. Juste été là. Sans parler. Sans servir. Sans animer. Ces trois moments de présence pure. Juste toi dans ta fête. Joyeuse fête, mon humain préféré.
Avec trois moments de présence pure collectés et leur valeur placée au sommet, — {prenom}, ton animal gardien de tes moments sans rôle 🌿$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de vérifier la cuisson.',$$Joyeuse fête. J''ai observé ta façon de vérifier la cuisson.
La fourchette qui pique. L''oreille tendue pour écouter le grésillement. Le nez qui évalue. Ces trois sens mobilisés pour décider si c''est prêt. Ce rituel de la vérification que tu fais automatiquement mais qui est en fait une expertise développée. Joyeuse fête, mon humain préféré.
Avec observation de ton expertise de cuisson à trois sens et admiration pour son automatisme, — {prenom}, ton animal dont les sens sont moins polyvalents en cuisine 🍳$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis face à une maladresse.',$$Joyeuse fête. J''ai observé comment tu réagis face à une maladresse.
Tu dédramatises immédiatement. Un mot. Un geste. Parfois tu ris avec eux. Toujours tu fais en sorte que la personne ne garde pas la maladresse comme souvenir de la soirée. Joyeuse fête, mon humain préféré.
Avec admiration pour ta dissolution des maladresses dans la chaleur générale, — {prenom}, ton animal expert en gestion de l''embarrassant 🙈$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils sont allergiques puis goûtent quand même.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils sont allergiques puis goûtent quand même.
Ce soir une personne allergique à quelque chose a quand même goûté le plat qui contenait ce quelque chose. En petite quantité elle a dit. Peut-être que les allergies ont des exceptions pour les bonnes fêtes. Je ne juge pas. Je note. Joyeuse fête, mon humain préféré.
Avec observation de l''allergie à géométrie variable et philosophie de l''exception festive, — {prenom}, ton animal dont les convictions alimentaires sont plus stables 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de poser la main sur la table quand tu parles.',$$Joyeuse fête. J''ai étudié ta façon de poser la main sur la table quand tu parles.
Pas posée. Ancrée. Comme si la table était un point de stabilité pendant que les mots partent. Cette main posée dit que tu es là. Que ce que tu dis vient de quelque part de solide. Joyeuse fête, mon humain préféré.
Avec observation de ta main ancrée comme point de stabilité conversationnelle, — {prenom}, ton animal lecteur de tes ancres 🖐️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de remarquer qu''un invité s''ennuie.',$$Joyeuse fête. J''ai observé ta façon de remarquer qu''un invité s''ennuie.
Tu le vois avant les autres. Ce légèrement en retrait. Ce regard qui fait un tour de la pièce. Et tu bouges vers lui. Tu t''assures qu''il existe dans la soirée. Joyeuse fête, mon humain préféré.
Avec admiration pour ta vigilance pour les marges et ton mouvement vers elles, — {prenom}, ton animal témoin de ton inclusion silencieuse 💛$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu t''occupes de quelqu''un qui a trop bu.',$$Joyeuse fête. J''ai observé comment tu t''occupes de quelqu''un qui a trop bu.
Sans le signaler. Sans le mettre en difficulté. Tu lui poses une question. Tu lui apportes de l''eau naturellement. Tu t''assures qu''il mange quelque chose. Cette façon de prendre soin sans humilier. Joyeuse fête, mon humain préféré.
Avec admiration pour ton soin discret sans jamais mettre quelqu''un en difficulté, — {prenom}, ton animal admirateur de ta grâce dans les moments délicats 💧$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les cadeaux sont dans du papier qui sera jeté.',$$Joyeuse fête. Je comprends pas pourquoi les cadeaux sont dans du papier qui sera jeté.
Ce soir plusieurs cadeaux sont arrivés dans du beau papier. Choisi avec soin. Qui a été ouvert et jeté. Ce sacrifice du beau pour révéler le beau. Joyeuse fête, mon humain préféré.
Avec réflexion poétique sur le sacrifice de l''emballage pour révéler le cadeau, — {prenom}, ton animal philosophe de l''emballage 🎀$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon de regarder les gens parler entre eux sans toi.',$$Joyeuse fête. J''ai mémorisé ta façon de regarder les gens parler entre eux sans toi.
Parfois tu t''arrêtais. Tu regardais deux ou trois personnes en conversation. Tu souriais. Ce sourire de créateur qui voit sa création fonctionner seule. Ces gens qui parlent entre eux grâce à toi. Grâce à ce que tu as créé ce soir. Joyeuse fête, mon humain préféré.
Avec observation de ton sourire créateur devant ta création autonome, — {prenom}, ton animal témoin de ta fierté silencieuse de fondateur 🌟$$,'humorous',true,false,'nameday','chien','from')

on conflict do nothing;
